import type { ToastManager as BaseToastManager, ToastObject } from '@base-ui/react/toast';
import { Toast as ToastPrimitive } from '@base-ui/react/toast';
import {
  createContext,
  Fragment,
  useContext,
  useMemo,
  type ComponentProps,
  type ReactNode,
} from 'react';
import { CloseIcon, PopupArrowIcon } from '@/lib/moduix/icons/ui';
import { mergeClassName } from '@/lib/moduix/mergeClassName';
import styles from './Toast.module.css';

export type ToastPlacement =
  | 'top-left'
  | 'top-center'
  | 'top-right'
  | 'bottom-left'
  | 'bottom-center'
  | 'bottom-right';
export type ToastStackBehavior = 'stacked' | 'expanded';
type ToastItem = ToastObject<any>;
type DataSlotProps = { 'data-slot'?: string };
export type AnchoredToastOptions = Omit<
  Parameters<BaseToastManager['add']>[0],
  'id' | 'positionerProps'
> & {
  anchor: Element;
  id?: string;
  positionerProps?: NonNullable<Parameters<BaseToastManager['add']>[0]['positionerProps']>;
};

const DEFAULT_TOAST_PLACEMENT: ToastPlacement = 'bottom-right';
const DEFAULT_STACK_BEHAVIOR: ToastStackBehavior = 'stacked';
const DEFAULT_ANCHORED_SIDE_OFFSET = 8;
const TOP_TOAST_SWIPE_DIRECTIONS: Array<'left' | 'right' | 'up'> = ['left', 'right', 'up'];
const BOTTOM_TOAST_SWIPE_DIRECTIONS: Array<'left' | 'right' | 'down'> = ['left', 'right', 'down'];

const ToastPlacementContext = createContext<ToastPlacement>(DEFAULT_TOAST_PLACEMENT);
const ToastStackBehaviorContext = createContext<ToastStackBehavior>(DEFAULT_STACK_BEHAVIOR);
const ToastStyleContext = createContext<'stacked' | 'anchored'>('stacked');
const AnchoredToastManagerContext = createContext<{
  manager: BaseToastManager;
  show: (options: AnchoredToastOptions) => string;
  closeByAnchor: (anchor: Element | null) => void;
  closeAll: () => void;
} | null>(null);

const createToastManager = ToastPrimitive.createToastManager;
const useToastManager = ToastPrimitive.useToastManager;

function isAnchoredToast(toast: ToastItem) {
  return Boolean(toast.positionerProps?.anchor);
}

function getToastSwipeDirection(placement: ToastPlacement) {
  return placement.startsWith('top') ? TOP_TOAST_SWIPE_DIRECTIONS : BOTTOM_TOAST_SWIPE_DIRECTIONS;
}

function ToastProvider({
  children,
  toastManager,
  anchoredToastManager,
  ...props
}: ToastPrimitive.Provider.Props & {
  anchoredToastManager?: BaseToastManager;
}) {
  const defaultToastManager = useMemo(() => createToastManager(), []);
  const defaultAnchoredToastManager = useMemo(() => createToastManager(), []);
  const resolvedToastManager = toastManager ?? defaultToastManager;
  const resolvedAnchoredToastManager = anchoredToastManager ?? defaultAnchoredToastManager;
  const anchoredToast = useMemo(
    () => createAnchoredToastManager(resolvedAnchoredToastManager),
    [resolvedAnchoredToastManager],
  );

  return (
    <AnchoredToastManagerContext.Provider value={anchoredToast}>
      <ToastPrimitive.Provider toastManager={resolvedToastManager} {...props}>
        {children}
      </ToastPrimitive.Provider>
    </AnchoredToastManagerContext.Provider>
  );
}

function ToastPortal({ className, ...props }: ToastPrimitive.Portal.Props) {
  return (
    <ToastPrimitive.Portal
      data-slot="toast-portal"
      className={mergeClassName(className, styles.portal)}
      {...props}
    />
  );
}

function ToastViewport({
  className,
  placement = DEFAULT_TOAST_PLACEMENT,
  stackBehavior = DEFAULT_STACK_BEHAVIOR,
  ...props
}: ToastPrimitive.Viewport.Props & {
  placement?: ToastPlacement;
  stackBehavior?: ToastStackBehavior;
}) {
  return (
    <ToastPlacementContext.Provider value={placement}>
      <ToastStackBehaviorContext.Provider value={stackBehavior}>
        <ToastPrimitive.Viewport
          data-slot="toast-viewport"
          data-placement={placement}
          data-stack-behavior={stackBehavior}
          className={mergeClassName(className, styles.viewport)}
          {...props}
        />
      </ToastStackBehaviorContext.Provider>
    </ToastPlacementContext.Provider>
  );
}

function ToastRoot(
  props: ToastPrimitive.Root.Props & {
    placement?: ToastPlacement;
  },
) {
  const { className, placement, swipeDirection, toast, ...rootProps } = props;
  const contextPlacement = useContext(ToastPlacementContext);
  const stackBehavior = useContext(ToastStackBehaviorContext);
  const anchored = isAnchoredToast(toast);
  const resolvedPlacement = placement ?? contextPlacement;
  const dataSlot = (props as DataSlotProps)['data-slot'];
  const toastType = toast.type;

  return (
    <ToastStyleContext.Provider value={anchored ? 'anchored' : 'stacked'}>
      <ToastPrimitive.Root
        {...rootProps}
        toast={toast}
        data-slot={dataSlot ?? (anchored ? 'toast-anchored-root' : 'toast-root')}
        data-placement={resolvedPlacement}
        data-stack-behavior={stackBehavior}
        data-type={toastType}
        swipeDirection={
          anchored ? swipeDirection : (swipeDirection ?? getToastSwipeDirection(resolvedPlacement))
        }
        className={mergeClassName(className, anchored ? styles.anchoredRoot : styles.root)}
      />
    </ToastStyleContext.Provider>
  );
}

function ToastContent(props: ToastPrimitive.Content.Props) {
  const { className, ...contentProps } = props;
  const style = useContext(ToastStyleContext);
  const stackBehavior = useContext(ToastStackBehaviorContext);
  const dataSlot = (props as DataSlotProps)['data-slot'];

  return (
    <ToastPrimitive.Content
      {...contentProps}
      data-slot={dataSlot ?? (style === 'anchored' ? 'toast-anchored-content' : 'toast-content')}
      data-stack-behavior={style === 'stacked' ? stackBehavior : undefined}
      className={mergeClassName(
        className,
        style === 'anchored' ? styles.anchoredContent : styles.content,
      )}
    />
  );
}

function ToastTitle({ className, ...props }: ToastPrimitive.Title.Props) {
  return (
    <ToastPrimitive.Title
      data-slot="toast-title"
      className={mergeClassName(className, styles.title)}
      {...props}
    />
  );
}

function ToastDescription(props: ToastPrimitive.Description.Props) {
  const { className, ...descriptionProps } = props;
  const style = useContext(ToastStyleContext);
  const dataSlot = (props as DataSlotProps)['data-slot'];

  return (
    <ToastPrimitive.Description
      {...descriptionProps}
      data-slot={
        dataSlot ?? (style === 'anchored' ? 'toast-anchored-description' : 'toast-description')
      }
      className={mergeClassName(
        className,
        style === 'anchored' ? styles.anchoredDescription : styles.description,
      )}
    />
  );
}

function ToastAction({ className, ...props }: ToastPrimitive.Action.Props) {
  return (
    <ToastPrimitive.Action
      data-slot="toast-action"
      className={mergeClassName(className, styles.action)}
      {...props}
    />
  );
}

function ToastClose({ className, children, ...props }: ToastPrimitive.Close.Props) {
  return (
    <ToastPrimitive.Close
      data-slot="toast-close"
      className={mergeClassName(className, styles.close)}
      {...props}
    >
      {children ?? <CloseIcon className={styles.closeIcon} />}
    </ToastPrimitive.Close>
  );
}

function ToastPositioner({ className, ...props }: ToastPrimitive.Positioner.Props) {
  return (
    <ToastPrimitive.Positioner
      data-slot="toast-positioner"
      className={mergeClassName(className, styles.positioner)}
      {...props}
    />
  );
}

function ToastArrow(props: ToastPrimitive.Arrow.Props) {
  const { className, children, ...arrowProps } = props;
  const dataSlot = (props as DataSlotProps)['data-slot'];

  return (
    <ToastPrimitive.Arrow
      {...arrowProps}
      data-slot={dataSlot ?? 'toast-anchored-arrow'}
      className={mergeClassName(className, styles.anchoredArrow)}
    >
      {children ?? <AnchoredArrowSvg className={styles.anchoredArrowSvg} />}
    </ToastPrimitive.Arrow>
  );
}

function ToastRegion({
  className,
  container,
  renderToast,
  placement = DEFAULT_TOAST_PLACEMENT,
  stackBehavior = DEFAULT_STACK_BEHAVIOR,
  ...props
}: Omit<ToastPrimitive.Viewport.Props, 'children'> & {
  placement?: ToastPlacement;
  stackBehavior?: ToastStackBehavior;
  container?: ToastPrimitive.Portal.Props['container'];
  renderToast?: (toast: ToastItem, index: number) => ReactNode;
}) {
  const { toasts: allToasts } = useToastManager();
  const toasts = allToasts.filter((toast) => !isAnchoredToast(toast));

  return (
    <ToastPortal container={container}>
      <ToastViewport
        placement={placement}
        stackBehavior={stackBehavior}
        className={className}
        {...props}
      >
        {toasts.map((toast, index) =>
          renderToast ? (
            <Fragment key={toast.id}>{renderToast(toast, index)}</Fragment>
          ) : (
            <DefaultToast key={toast.id} toast={toast} />
          ),
        )}
      </ToastViewport>
    </ToastPortal>
  );
}

function ToastAnchoredRegion({
  className,
  container,
  renderToast,
  ...props
}: Omit<ToastPrimitive.Viewport.Props, 'children'> & {
  container?: ToastPrimitive.Portal.Props['container'];
  renderToast?: (toast: ToastItem, index: number) => ReactNode;
}) {
  const anchoredToast = useContext(AnchoredToastManagerContext);

  if (!anchoredToast) {
    throw new Error('ToastAnchoredRegion must be used within ToastProvider.');
  }

  return (
    <ToastPrimitive.Provider toastManager={anchoredToast.manager}>
      <ToastAnchoredRegionContent
        className={className}
        container={container}
        renderToast={renderToast}
        {...props}
      />
    </ToastPrimitive.Provider>
  );
}

function ToastAnchoredRegionContent({
  className,
  container,
  renderToast,
  ...props
}: Omit<ToastPrimitive.Viewport.Props, 'children'> & {
  container?: ToastPrimitive.Portal.Props['container'];
  renderToast?: (toast: ToastItem, index: number) => ReactNode;
}) {
  const { toasts } = useToastManager();

  return (
    <ToastPortal container={container}>
      <ToastPrimitive.Viewport
        data-slot="toast-anchored-viewport"
        className={mergeClassName(className, styles.anchoredViewport)}
        {...props}
      >
        {toasts.map((toast, index) => (
          <ToastPositioner key={toast.id} toast={toast} className={styles.anchoredPositioner}>
            {renderToast ? renderToast(toast, index) : <DefaultAnchoredToast toast={toast} />}
          </ToastPositioner>
        ))}
      </ToastPrimitive.Viewport>
    </ToastPortal>
  );
}

function DefaultToast({ toast }: { toast: ToastItem }) {
  return (
    <ToastRoot toast={toast}>
      <ToastContent>
        <ToastTitle />
        <ToastDescription />
        {toast.actionProps ? <ToastAction /> : null}
        <ToastClose aria-label="Close toast" />
      </ToastContent>
    </ToastRoot>
  );
}

function DefaultAnchoredToast({ toast }: { toast: ToastItem }) {
  return (
    <ToastRoot toast={toast}>
      <ToastArrow />
      <ToastContent>
        <ToastDescription />
      </ToastContent>
    </ToastRoot>
  );
}

function AnchoredArrowSvg(props: ComponentProps<'svg'>) {
  return (
    <PopupArrowIcon
      fillClassName={styles.anchoredArrowFill}
      outerStrokeClassName={styles.anchoredArrowOuterStroke}
      innerStrokeClassName={styles.anchoredArrowInnerStroke}
      {...props}
    />
  );
}

function createAnchoredToastManager(manager: BaseToastManager = createToastManager()) {
  const anchorIds = new WeakMap<Element, string>();
  let idCounter = 0;

  const show = ({ anchor, id, positionerProps, onRemove, ...options }: AnchoredToastOptions) => {
    const existingId = anchorIds.get(anchor);
    const resolvedId = existingId ?? id ?? `anchored-${Date.now()}-${++idCounter}`;

    manager.add({
      ...options,
      id: resolvedId,
      positionerProps: {
        sideOffset: DEFAULT_ANCHORED_SIDE_OFFSET,
        ...positionerProps,
        anchor,
      },
      onRemove: () => {
        if (anchorIds.get(anchor) === resolvedId) {
          anchorIds.delete(anchor);
        }

        onRemove?.();
      },
    });

    anchorIds.set(anchor, resolvedId);

    return resolvedId;
  };

  const closeByAnchor = (anchor: Element | null) => {
    if (!anchor) {
      return;
    }

    const toastId = anchorIds.get(anchor);

    if (!toastId) {
      return;
    }

    manager.close(toastId);
    anchorIds.delete(anchor);
  };

  const closeAll = () => {
    manager.close();
  };

  return { manager, show, closeByAnchor, closeAll };
}

function useAnchoredToastManager() {
  const anchoredToast = useContext(AnchoredToastManagerContext);

  if (!anchoredToast) {
    throw new Error('useAnchoredToastManager must be used within ToastProvider.');
  }

  return anchoredToast;
}

export {
  ToastProvider,
  ToastPortal,
  ToastViewport,
  ToastRoot,
  ToastContent,
  ToastTitle,
  ToastDescription,
  ToastAction,
  ToastClose,
  ToastPositioner,
  ToastArrow,
  ToastRegion,
  ToastAnchoredRegion,
  createToastManager,
  useToastManager,
  useAnchoredToastManager,
};

@layer ui.components {
  .portal {
    z-index: var(--toast-z-index, var(--z-toast));
  }

  .viewport {
    position: fixed;
    z-index: var(--toast-z-index, var(--z-toast));
    width: var(--toast-viewport-width, 20rem);
    max-width: calc(100vw - (var(--toast-viewport-inset, 1rem) * 2));
    min-height: 1px;
    margin: 0 auto;

    &[data-placement^='top'] {
      top: var(--toast-viewport-inset, 1rem);
      bottom: auto;
    }

    &[data-placement^='bottom'] {
      top: auto;
      bottom: var(--toast-viewport-inset, 1rem);
    }

    &[data-placement$='left'] {
      left: var(--toast-viewport-inset, 1rem);
      right: auto;
    }

    &[data-placement$='center'] {
      left: 50%;
      right: auto;
      translate: -50% 0;
    }

    &[data-placement$='right'] {
      left: auto;
      right: var(--toast-viewport-inset, 1rem);
    }
  }

  .anchoredViewport {
    outline: 0;
  }

  .anchoredPositioner {
    z-index: calc(var(--toast-z-index, var(--z-toast)) - var(--toast-index));
  }

  .anchoredRoot {
    position: relative;
    box-sizing: border-box;
    display: flex;
    width: max-content;
    max-width: min(
      var(--toast-anchored-max-width, 20rem),
      calc(100vw - (var(--toast-viewport-inset, 1rem) * 2))
    );
    flex-direction: column;
    border-radius: var(--toast-radius, var(--radius-md));
    background-color: var(--toast-bg, var(--toast-bg-default, var(--color-popover)));
    color: var(--toast-color, var(--toast-color-default, var(--color-popover-foreground)));
    padding: var(--toast-anchored-padding-y, 0.25rem) var(--toast-anchored-padding-x, 0.5rem);
    font-size: var(--toast-anchored-font-size, var(--text-sm));
    line-height: var(--toast-anchored-line-height, var(--line-height-text-sm));
    box-shadow: var(--toast-shadow, var(--shadow-lg));
    outline: var(--toast-border-width, var(--border-width-sm)) solid
      var(--toast-border-color, var(--toast-border-color-default, var(--color-border)));
    pointer-events: auto;
    transform-origin: var(--transform-origin);
    transition: var(--toast-anchored-transition, transform 150ms, opacity 150ms);

    &[data-starting-style],
    &[data-ending-style] {
      opacity: 0;
      transform: scale(var(--toast-anchored-scale, 0.9));
    }

    &:focus-visible {
      outline: var(--toast-focus-ring-width, var(--toast-border-width, var(--border-width-sm)))
        solid var(--toast-focus-ring-color, var(--color-ring));
      outline-offset: var(--toast-focus-ring-offset, 0);
    }
  }

  .root,
  .anchoredRoot {
    &[data-type='info'] {
      --toast-bg-default: color-mix(in oklab, var(--color-primary) 4%, var(--color-background));
      --toast-border-color-default: color-mix(in oklab, var(--color-primary) 32%, transparent);
      --toast-close-bg-hover-default: color-mix(in oklab, var(--color-primary) 10%, transparent);
      --toast-close-color-default: var(--color-primary);
      --toast-close-color-hover-default: var(--color-primary);
      --toast-color-default: var(--color-foreground);
      --toast-description-color-default: var(--color-muted-foreground);
    }

    &[data-type='success'] {
      --toast-bg-default: color-mix(in oklab, var(--color-success) 10%, var(--color-background));
      --toast-border-color-default: color-mix(in oklab, var(--color-success) 34%, transparent);
      --toast-close-bg-hover-default: color-mix(in oklab, var(--color-success) 12%, transparent);
      --toast-close-color-default: var(--color-success);
      --toast-close-color-hover-default: var(--color-success);
      --toast-color-default: var(--color-foreground);
      --toast-description-color-default: var(--color-muted-foreground);
    }

    &[data-type='warning'] {
      --toast-bg-default: color-mix(in oklab, var(--color-warning) 13%, var(--color-background));
      --toast-border-color-default: color-mix(in oklab, var(--color-warning) 38%, transparent);
      --toast-close-bg-hover-default: color-mix(in oklab, var(--color-warning) 14%, transparent);
      --toast-close-color-default: var(--color-warning);
      --toast-close-color-hover-default: var(--color-warning);
      --toast-color-default: var(--color-foreground);
      --toast-description-color-default: var(--color-muted-foreground);
    }

    &[data-type='destructive'],
    &[data-type='error'] {
      --toast-bg-default: color-mix(in oklab, var(--color-destructive) 9%, var(--color-background));
      --toast-border-color-default: color-mix(in oklab, var(--color-destructive) 35%, transparent);
      --toast-close-bg-hover-default: color-mix(
        in oklab,
        var(--color-destructive) 10%,
        transparent
      );
      --toast-close-color-default: var(--color-destructive);
      --toast-close-color-hover-default: var(--color-destructive);
      --toast-color-default: var(--color-foreground);
      --toast-description-color-default: var(--color-muted-foreground);
    }
  }

  .anchoredArrow {
    display: flex;
    color: var(--toast-bg, var(--toast-bg-default, var(--color-popover)));

    &[data-side='top'] {
      bottom: var(--toast-anchored-arrow-offset-y, -8px);
      rotate: 180deg;
    }

    &[data-side='bottom'] {
      top: var(--toast-anchored-arrow-offset-y, -8px);
      rotate: 0deg;
    }

    &[data-side='left'] {
      right: var(--toast-anchored-arrow-offset-x, -13px);
      rotate: 90deg;
    }

    &[data-side='right'] {
      left: var(--toast-anchored-arrow-offset-x, -13px);
      rotate: -90deg;
    }
  }

  .anchoredArrowSvg {
    display: block;
    width: var(--toast-anchored-arrow-width, 1.25rem);
    height: var(--toast-anchored-arrow-height, 0.625rem);
    shape-rendering: geometricPrecision;
  }

  .anchoredArrowFill {
    fill: currentColor;
  }

  .anchoredArrowOuterStroke {
    fill: var(--toast-border-color, var(--toast-border-color-default, var(--color-border)));
  }

  .anchoredArrowInnerStroke {
    fill: var(--toast-bg, var(--toast-bg-default, var(--color-popover)));
  }

  .anchoredContent {
    display: grid;
    align-items: center;
    gap: var(--toast-content-gap, 0.25rem);
  }

  .anchoredDescription {
    margin: 0;
    color: inherit;
  }

  .root {
    --gap: var(--toast-stack-gap, 0.75rem);
    --peek: var(--toast-stack-peek, 0.75rem);
    --scale: calc(max(0, 1 - (var(--toast-index) * 0.1)));
    --shrink: calc(1 - var(--scale));
    --height: var(--toast-frontmost-height, var(--toast-height));
    --offset-y: calc(
      var(--toast-offset-y) * -1 + (var(--toast-index) * var(--gap) * -1) +
        var(--toast-swipe-movement-y)
    );
    position: absolute;
    right: 0;
    bottom: 0;
    left: auto;
    margin-right: 0;
    box-sizing: border-box;
    width: 100%;
    border: var(--toast-border-width, var(--border-width-sm)) solid
      var(--toast-border-color, var(--toast-border-color-default, var(--color-border)));
    border-radius: var(--toast-radius, var(--radius-lg));
    background-color: var(--toast-bg, var(--toast-bg-default, var(--color-popover)));
    color: var(--toast-color, var(--toast-color-default, var(--color-popover-foreground)));
    box-shadow: var(--toast-shadow, var(--shadow-lg));
    background-clip: padding-box;
    padding: var(--toast-padding, 1rem);
    user-select: none;
    pointer-events: auto;
    transition:
      transform var(--toast-transition, 0.5s cubic-bezier(0.22, 1, 0.36, 1)),
      opacity 0.5s,
      height 150ms ease;
    z-index: calc(var(--toast-z-index, var(--z-toast)) - var(--toast-index));
    height: var(--height);
    transform: translateX(var(--toast-swipe-movement-x))
      translateY(
        calc(
          var(--toast-swipe-movement-y) - (var(--toast-index) * var(--peek)) -
            (var(--shrink) * var(--height))
        )
      )
      scale(var(--scale));
    transform-origin: bottom center;

    &[data-placement^='top'] {
      --offset-y: calc(
        var(--toast-offset-y) + (var(--toast-index) * var(--gap)) + var(--toast-swipe-movement-y)
      );
      top: 0;
      right: 0;
      bottom: auto;
      left: 0;
      margin-right: auto;
      margin-left: auto;
      transform: translateX(var(--toast-swipe-movement-x))
        translateY(
          calc(
            var(--toast-swipe-movement-y) + (var(--toast-index) * var(--peek)) +
              (var(--shrink) * var(--height))
          )
        )
        scale(var(--scale));
      transform-origin: top center;
    }

    &[data-expanded] {
      transform: translateX(var(--toast-swipe-movement-x)) translateY(var(--offset-y));
      height: var(--toast-height);
    }

    &[data-stack-behavior='expanded']:not([data-starting-style]):not([data-ending-style]) {
      transform: translateX(var(--toast-swipe-movement-x)) translateY(var(--offset-y));
      height: var(--toast-height);
    }

    &[data-starting-style] {
      transform: translateY(150%);

      &[data-placement^='top'] {
        transform: translateY(-150%);
      }
    }

    &[data-limited] {
      opacity: 0;
    }

    &[data-ending-style] {
      opacity: 0;

      &:not([data-limited]):not([data-swipe-direction]) {
        transform: translateY(150%);

        &[data-placement^='top'] {
          transform: translateY(-150%);
        }
      }

      &[data-swipe-direction='up'] {
        transform: translateY(calc(var(--toast-swipe-movement-y) - 150%));
      }

      &[data-swipe-direction='left'] {
        transform: translateX(calc(var(--toast-swipe-movement-x) - 150%))
          translateY(var(--offset-y));
      }

      &[data-swipe-direction='right'] {
        transform: translateX(calc(var(--toast-swipe-movement-x) + 150%))
          translateY(var(--offset-y));
      }

      &[data-swipe-direction='down'] {
        transform: translateY(calc(var(--toast-swipe-movement-y) + 150%));
      }
    }

    &::after {
      content: '';
      position: absolute;
      top: 100%;
      left: 0;
      width: 100%;
      height: calc(var(--gap) + var(--toast-border-width, var(--border-width-sm)));
    }

    &[data-placement^='top'] {
      &::after {
        top: auto;
        bottom: 100%;
      }
    }
  }

  .content {
    display: grid;
    gap: var(--toast-content-gap, 0.25rem);
    overflow: hidden;
    padding-inline-end: calc(
      var(--toast-close-offset-right, 0.5rem) + var(--toast-close-size, 1.25rem) + var(--spacing-2)
    );
    transition: opacity 250ms ease;

    &[data-behind] {
      opacity: 0;
      pointer-events: none;
    }

    &[data-expanded],
    &[data-stack-behavior='expanded'] {
      opacity: 1;
      pointer-events: auto;
    }
  }

  .title {
    margin: 0;
    color: inherit;
    font-size: var(--toast-title-font-size, var(--text-sm));
    font-weight: var(--toast-title-font-weight, var(--weight-semibold));
    line-height: var(--toast-title-line-height, var(--line-height-text-sm));
  }

  .description {
    margin: 0;
    color: var(
      --toast-description-color,
      var(--toast-description-color-default, var(--color-muted-foreground))
    );
    font-size: var(--toast-description-font-size, var(--text-sm));
    line-height: var(--toast-description-line-height, var(--line-height-text-sm));
  }

  .action {
    margin-top: var(--toast-action-margin-top, 0.5rem);
    border: var(--toast-action-border-width, var(--toast-border-width, var(--border-width-sm)))
      solid var(--toast-action-border-color, var(--color-border));
    border-radius: var(--toast-action-radius, var(--radius-sm));
    background: var(--toast-action-bg, var(--color-background));
    color: var(--toast-action-color, var(--color-foreground));
    padding: var(--toast-action-padding-y, 0.25rem) var(--toast-action-padding-x, 0.5rem);
    font-size: var(--toast-action-font-size, var(--text-xs));
    line-height: var(--toast-action-line-height, var(--line-height-text-xs));
    font-weight: var(--toast-action-font-weight, var(--weight-medium));
    cursor: pointer;

    &:focus-visible {
      outline: var(--toast-focus-ring-width, var(--toast-border-width, var(--border-width-sm)))
        solid var(--toast-focus-ring-color, var(--color-ring));
      outline-offset: calc(
        var(--toast-focus-ring-width, var(--toast-border-width, var(--border-width-sm))) * -1
      );
    }

    &:disabled,
    &[data-disabled] {
      cursor: default;
      opacity: var(--opacity-disabled);
    }

    @media (hover: hover) {
      &:hover:not(:disabled):not([data-disabled]) {
        background-color: var(--toast-action-bg-hover, var(--color-accent));
      }
    }
  }

  .close {
    position: absolute;
    top: var(--toast-close-offset-top, 0.5rem);
    right: var(--toast-close-offset-right, 0.5rem);
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: var(--toast-close-size, 1.25rem);
    height: var(--toast-close-size, 1.25rem);
    border: none;
    border-radius: var(--toast-close-radius, var(--radius-sm));
    background: var(--toast-close-bg, transparent);
    color: var(
      --toast-close-color,
      var(--toast-close-color-default, var(--color-muted-foreground))
    );
    padding: var(--toast-close-padding, 0);
    cursor: pointer;

    @media (hover: hover) {
      &:hover {
        background-color: var(
          --toast-close-bg-hover,
          var(--toast-close-bg-hover-default, var(--color-accent))
        );
        color: var(
          --toast-close-color-hover,
          var(--toast-close-color-hover-default, var(--color-foreground))
        );
      }
    }

    &:focus-visible {
      outline: var(--toast-focus-ring-width, var(--toast-border-width, var(--border-width-sm)))
        solid var(--toast-focus-ring-color, var(--color-ring));
      outline-offset: var(--toast-close-focus-ring-offset, 0);
    }
  }

  .closeIcon {
    width: var(--toast-close-icon-size, 1rem);
    height: var(--toast-close-icon-size, 1rem);
  }

  .positioner {
    pointer-events: none;
  }
}
